#!/usr/bin/env node
// Regenerates apps/desktop/src/types/generated/index.ts as a barrel
// re-export of every *.ts file ts-rs has dropped into the directory.
//
// Invoke via `pnpm typegen` (which also runs `cargo test` to refresh
// the source bindings).

import { promises as fs } from 'node:fs'
import path from 'node:path'
import { fileURLToPath } from 'node:url'

const here = path.dirname(fileURLToPath(import.meta.url))
const generatedDir = path.resolve(here, '..', 'apps/desktop/src/types/generated')

const HEADER =
	'// This file is generated by `pnpm typegen`. Do not edit by hand.\n' +
	'// It re-exports every ts-rs binding in this directory.\n\n'

async function main() {
	const entries = await fs.readdir(generatedDir)
	const types = entries
		.filter((f) => f.endsWith('.ts') && f !== 'index.ts')
		.map((f) => f.replace(/\.ts$/, ''))
		.sort()

	const lines = types.map((t) => `export type { ${t} } from './${t}'`)
	const content = `${HEADER}${lines.join('\n')}\n`

	const indexPath = path.join(generatedDir, 'index.ts')
	await fs.writeFile(indexPath, content)
	process.stdout.write(`Wrote ${indexPath} with ${types.length} re-exports\n`)
}

main().catch((err) => {
	console.error(err)
	process.exit(1)
})
